Here is C++ code to read a text file line by line and count the occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <string>
using namespace std;

int main() {
  ifstream infile("input.txt");
  string line;
  string word = "example"; 
  int count = 0;

  if(infile.is_open()) {
    while(getline(infile, line)) {
      size_t pos = 0;
      while((pos = line.find(word, pos)) != string::npos) {
         count++;
         pos += word.length();
      }
    }
    infile.close();
  }
  else {
    cout << "Unable to open file"; 
  }

  cout << "The word " << word << " appears " << count << " times.";

  return 0;
}
```

The key steps are:

1. Open the input text file using ifstream
2. Read each line using getline()
3. Use find() to search for the word in each line 
4. Increment count each time the word is found
5. Close the file after reading all lines
6. Print out total count

